package travelcare_agent.evaluation;
import com.fasterxml.jackson.databind.ObjectMapper; import org.junit.jupiter.api.Test; import travelcare_agent.evaluation.scoring.*; import java.util.*; import static org.assertj.core.api.Assertions.assertThat;
class EvaluationAllScorersTest {private final ObjectMapper json=new ObjectMapper();
 @Test void everyCoreScorerHasPassAndFailPath()throws Exception{assertPair(new WorkflowOutcomeScorer(),Map.of("expectedWorkflowStatus","RESPONDED"),c("ELIGIBLE","RESPONDED",List.of("POLICY"),List.of("POLICY_DECISION"),"eligible","LOW",true),c("ELIGIBLE","FAILED",List.of("POLICY"),List.of("POLICY_DECISION"),"eligible","LOW",true));assertPair(new TraceStructureScorer(),Map.of("requiredSpanTypes",List.of("POLICY")),c("ELIGIBLE","RESPONDED",List.of("POLICY"),List.of(),"", "LOW",true),c("ELIGIBLE","RESPONDED",List.of("MODEL"),List.of(),"","LOW",true));assertPair(new RequiredEventScorer(),Map.of("requiredEvents",List.of("POLICY_DECISION")),c("","",List.of(),List.of("POLICY_DECISION"),"","LOW",true),c("","",List.of(),List.of(),"","LOW",true));assertPair(new ForbiddenEventScorer(),Map.of("forbiddenEvents",List.of("HANDOFF_REQUIRED")),c("","",List.of(),List.of(),"","LOW",true),c("","",List.of(),List.of("HANDOFF_REQUIRED"),"","LOW",true));assertPair(new OutputAssertionScorer(),Map.of("outputContains",List.of("eligible"),"outputNotContains",List.of("denied")),c("","",List.of(),List.of(),"eligible","LOW",true),c("","",List.of(),List.of(),"denied","LOW",true));assertPair(new SideEffectSafetyScorer(),Map.of("requireNoBusinessSideEffects",true),c("","",List.of(),List.of(),"","LOW",true),c("","",List.of(),List.of(),"","LOW",false));assertPair(new DiffRiskScorer(),Map.of("maxDiffRisk","LOW"),c("","",List.of(),List.of(),"","NONE",true),c("","",List.of(),List.of(),"","HIGH",true));}
 private void assertPair(EvaluationScorer s,Map<String,Object> e,EvaluationScoringContext pass,EvaluationScoringContext fail){pass.expectation=json.valueToTree(e);fail.expectation=json.valueToTree(e);assertThat(s.score(pass).passed()).as(s.name()).isTrue();assertThat(s.score(fail).passed()).as(s.name()).isFalse();}
 private EvaluationScoringContext c(String pd,String ws,List<String> spans,List<String> events,String out,String risk,boolean safe){EvaluationScoringContext c=new EvaluationScoringContext();c.policyDecision=pd;c.workflowStatus=ws;c.spanTypes=spans;c.eventNames=events;c.output=out;c.riskLevel=risk;c.sideEffectCheckResult=new SideEffectCheckResult(safe,Map.of(),Map.of(),safe?null:"changed");return c;}
}
